search.taxonomies:
{%- for taxonomy in config.taxonomies %}


  {{taxonomy.name}}
  {% set taxonomy = get_taxonomy(kind=taxonomy.name) %}{%- for term in taxonomy.items %}


      {{term.name | escape_xml | safe }}{% set page = get_page(path="static/search.md") %}
      {{ page.permalink | escape_xml | safe }}?q={{term.name}}

    {%- endfor %}


{%- endfor %}

search.pages:
{%- for page in pages %}



      {{ page.title | escape_xml | safe }}
      {%- if page.authors -%}{{ page.authors[0] }}{%- elif config.author -%}{{ config.author }}{%- else -%}Unknown{%- endif -%}{% if page.extra.image is defined %}{% set img = resize_image(path=page.colocated_path ~ page.extra.image, width=512, op="fit_width") %}
      {{ img.url | escape_xml | safe }}{% endif %}
      {{ page.permalink | escape_xml | safe }}
      {{ page.description | escape_xml | safe }}
      {{ page.date | date(locale=date_locale, format=date_format) }}
      {% if page.extra.cooking_time is defined %}{{ page.extra.cooking_time | safe }} {{ res.reading_time }}{% endif %}


      {%- if page.taxonomies.tags %}{%- for tag in page.taxonomies.tags %}
{{ tag | escape_xml }}{%- endfor %}{%- endif %}
      {%- if page.taxonomies.ingredients %}{%- for ingredient in page.taxonomies.ingredients %}
{{ ingredient | escape_xml }}{%- endfor %}{%- endif %}
      {%- if page.taxonomies.seasons %}{%- for season in page.taxonomies.seasons %}
{{ season | escape_xml }}{%- endfor %}{%- endif %}
      {%- if page.taxonomies.tools %}{%- for tool in page.taxonomies.tools %}
{{ tool | escape_xml }}{%- endfor %}{%- endif %}

  {%- endfor %}
